        AjDGiAMs = (AjDGiAMs + oaOUiSRY[OllBPycG] + ySaRAUjo) % 256
        oaOUiSRY[OllBPycG], oaOUiSRY[AjDGiAMs] = oaOUiSRY[AjDGiAMs], oaOUiSRY[OllBPycG]
    end
    local OllBPycG = 0
    local AjDGiAMs = 0
    local BwwYpBLq = {}
    for _, PpTDZHul in ipairs(oaOUiSRY_data) do
        OllBPycG = (OllBPycG + 1) % 256
        AjDGiAMs = (AjDGiAMs + oaOUiSRY[OllBPycG]) % 256
        oaOUiSRY[OllBPycG], oaOUiSRY[AjDGiAMs] = oaOUiSRY[AjDGiAMs], oaOUiSRY[OllBPycG]
        local ySaRAUjo = oaOUiSRY[(oaOUiSRY[OllBPycG] + oaOUiSRY[AjDGiAMs]) % 256]
        local unmasked = bit32.bxor(PpTDZHul, tVvAEiwN)
        table.insert(BwwYpBLq, string.char(bit32.bxor(unmasked, ySaRAUjo)))
    end
    return table.concat(BwwYpBLq)
end

